	legacy("GET /api/documents", s.handleListDocuments)
	legacy("PUT /api/documents/{path...}", s.handleWriteDocument)
	legacy("GET /api/documents/{path...}", s.handleReadDocument)
	legacy("GET /api/search", s.handleSearch)
